import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../core/services/auth.service';
import { DepartmentService, UserService, TeamService } from '../../core/services/api.services';
import { Department, User, Team } from '../../core/models';

@Component({ selector: 'app-departments', templateUrl: './departments.component.html' })
export class DepartmentsComponent implements OnInit {
  departments: Department[] = [];
  // Head candidates — all users in that dept when editing, all non-PM users when creating
  headCandidates: User[] = [];
  teamMap: Record<number, Team[]> = {};
  loading = true;
  showForm = false;
  showDelConfirm = false;
  formMode: 'create' | 'edit' = 'create';
  selected: Department | null = null;
  saving = false;
  form: any = { name: '', description: '', headId: null };

  constructor(public auth: AuthService, private deptService: DepartmentService,
    private userService: UserService, private teamService: TeamService) {}

  ngOnInit(): void { this.load(); }

  load(): void {
    this.loading = true;
    this.deptService.getAll().subscribe(r => {
      if (r.success) {
        this.departments = r.data;
        r.data.forEach(d => {
          this.teamService.getByDept(d.id).subscribe(tr => {
            if (tr.success) this.teamMap[d.id] = tr.data;
          });
        });
      }
      this.loading = false;
    });
  }

  getTeams(deptId: number): Team[] { return this.teamMap[deptId] || []; }

  loadHeadCandidates(deptId: number | null): void {
    if (deptId) {
      // Show all approved users already in that department
      this.userService.getByDept(deptId).subscribe(r => {
        if (r.success) this.headCandidates = r.data.filter(u => u.approvalStatus === 'APPROVED');
      });
    } else {
      // New dept: show all approved non-PM users
      this.userService.getAll().subscribe(r => {
        if (r.success) this.headCandidates = r.data.filter(u =>
          u.approvalStatus === 'APPROVED' && u.role !== 'PROJECT_MANAGER');
      });
    }
  }

  openCreate(): void {
    this.formMode = 'create';
    this.form = { name: '', description: '', headId: null };
    this.loadHeadCandidates(null);
    this.showForm = true;
  }

  openEdit(d: Department): void {
    this.formMode = 'edit';
    this.selected = d;
    this.form = { name: d.name, description: d.description || '', headId: d.head?.id || null };
    // Load all people in this dept so any can be made head
    this.loadHeadCandidates(d.id);
    this.showForm = true;
  }

  save(): void {
    if (!this.form.name) return;
    this.saving = true;
    const obs = this.formMode === 'create'
      ? this.deptService.create(this.form)
      : this.deptService.update(this.selected!.id, this.form);
    obs.subscribe(r => {
      this.saving = false;
      if (r.success) { this.showForm = false; this.load(); }
    });
  }

  confirmDelete(d: Department): void { this.selected = d; this.showDelConfirm = true; }
  doDelete(): void {
    this.deptService.delete(this.selected!.id).subscribe(r => {
      if (r.success) { this.showDelConfirm = false; this.load(); }
    });
  }
}
<div class="fade-in">
  <div class="page-header">
    <div>
      <div class="page-title">Departments</div>
      <div class="page-subtitle">{{ departments.length }} department{{ departments.length !== 1 ? 's' : '' }}</div>
    </div>
    <button class="btn btn-primary" (click)="openCreate()">+ New Department</button>
  </div>

  <div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>

  <div *ngIf="!loading && departments.length === 0" class="card empty-state" style="padding:60px">
    <div class="empty-icon">⬢</div>
    <div class="empty-title">No departments yet</div>
  </div>

  <div *ngIf="!loading" class="grid-cards">
    <div *ngFor="let d of departments" class="info-card">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:14px">
        <div style="display:flex;align-items:center;gap:10px">
          <div style="width:42px;height:42px;border-radius:10px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0">🏢</div>
          <div>
            <div style="font-weight:700;font-size:15px">{{ d.name }}</div>
            <div *ngIf="d.description" style="font-size:12px;color:var(--text-muted)">{{ d.description }}</div>
          </div>
        </div>
        <div style="display:flex;gap:6px">
          <button class="btn btn-icon btn-sm" (click)="openEdit(d)" title="Edit">✏</button>
          <button class="btn btn-icon btn-sm btn-danger-ghost" (click)="confirmDelete(d)" title="Delete">✕</button>
        </div>
      </div>

      <!-- Head -->
      <div *ngIf="d.head" style="display:flex;align-items:center;gap:8px;padding:8px 12px;background:var(--bg-hover);border-radius:var(--radius-sm);margin-bottom:12px">
        <div class="avatar" style="width:28px;height:28px;font-size:11px">{{ d.head.firstName[0] }}{{ d.head.lastName[0] }}</div>
        <div>
          <div style="font-size:11px;color:var(--text-muted)">Department Head</div>
          <div style="font-size:13px;font-weight:600">{{ d.head.firstName }} {{ d.head.lastName }}</div>
        </div>
      </div>
      <div *ngIf="!d.head" style="padding:8px 12px;background:var(--bg-hover);border-radius:var(--radius-sm);font-size:13px;color:var(--text-muted);margin-bottom:12px">
        No department head assigned
      </div>

      <!-- Teams -->
      <div style="padding-top:10px;border-top:1px solid var(--border)">
        <div style="font-size:11px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.4px;margin-bottom:8px">
          Teams ({{ getTeams(d.id).length }})
        </div>
        <div *ngIf="getTeams(d.id).length === 0" style="font-size:12px;color:var(--text-muted)">No teams yet</div>
        <div style="display:flex;flex-wrap:wrap;gap:6px">
          <span *ngFor="let t of getTeams(d.id)" class="badge badge-blue">{{ t.name }}</span>
        </div>
      </div>
    </div>
  </div>
</div>

<!-- Form Modal -->
<div class="modal-overlay" *ngIf="showForm" (click)="showForm=false">
  <div class="modal" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <div class="modal-title">{{ formMode === 'create' ? 'New Department' : 'Edit Department' }}</div>
      <button class="modal-close" (click)="showForm=false">×</button>
    </div>
    <div class="modal-body">
      <div class="form-group">
        <label class="form-label">Name *</label>
        <input class="form-control" [(ngModel)]="form.name" placeholder="e.g. Development">
      </div>
      <div class="form-group">
        <label class="form-label">Description</label>
        <textarea class="form-control" [(ngModel)]="form.description" rows="2" placeholder="Brief description..."></textarea>
      </div>
      <div class="form-group">
        <label class="form-label">Department Head</label>
        <select class="form-control" [(ngModel)]="form.headId">
          <option [ngValue]="null">No head assigned</option>
          <option *ngFor="let u of headCandidates" [ngValue]="u.id">{{ u.firstName }} {{ u.lastName }} ({{ u.role }})</option>
        </select>
      </div>
    </div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showForm=false">Cancel</button>
      <button class="btn btn-primary" (click)="save()" [disabled]="saving || !form.name">
        {{ saving ? 'Saving...' : (formMode === 'create' ? 'Create' : 'Save Changes') }}
      </button>
    </div>
  </div>
</div>

<!-- Delete Confirm -->
<div class="modal-overlay" *ngIf="showDelConfirm" (click)="showDelConfirm=false">
  <div class="modal modal-sm" (click)="$event.stopPropagation()">
    <div class="modal-header"><div class="modal-title" style="color:var(--danger)">Delete Department</div></div>
    <div class="modal-body"><p>Delete "<strong>{{ selected?.name }}</strong>"? This cannot be undone.</p></div>
    <div class="modal-footer">
      <button class="btn btn-outline" (click)="showDelConfirm=false">Cancel</button>
      <button class="btn btn-danger" (click)="doDelete()">Delete</button>
    </div>
  </div>
</div>
